import React, { useState, useEffect } from 'react';
import { ShoppingCart, MapPin, Store, Plus, Loader2, Package, ChevronRight } from 'lucide-react';
import { api } from '../services/api';
import { useCart } from '../context/CartContext';

const PanelCliente = () => {
    const [ofertasPorLocal, setOfertasPorLocal] = useState({});
    const [loading, setLoading] = useState(true);
    const [userLocation, setUserLocation] = useState(null);
    const { addToCart, count, total, clearCart, cart } = useCart();

    // 1. Obtener ubicación del usuario para calcular distancia
    useEffect(() => {
        navigator.geolocation.getCurrentPosition(
            (pos) => setUserLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
            () => console.log("Ubicación no permitida")
        );
    }, []);

    // 2. Cargar y Agrupar Ofertas
    useEffect(() => {
        const cargarDatos = async () => {
            try {
                setLoading(true);
                const data = await api.getTodasLasOfertas();
                
                // AGRUPAR POR LOCAL
                const agrupado = data.reduce((acc, oferta) => {
                    const localNombre = oferta.local?.nombre || 'General';
                    if (!acc[localNombre]) acc[localNombre] = { info: oferta.local, productos: [] };
                    acc[localNombre].productos.push(oferta);
                    return acc;
                }, {});

                setOfertasPorLocal(agrupado);
            } catch (err) {
                console.error("Error:", err);
            } finally {
                setLoading(false);
            }
        };
        cargarDatos();
    }, []);

    // Función simple de distancia (KM)
    const calcularDistancia = (localCoords) => {
        if (!userLocation || !localCoords?.lat) return "Distancia N/A";
        const R = 6371; // Radio tierra
        const dLat = (localCoords.lat - userLocation.lat) * Math.PI / 180;
        const dLon = (localCoords.lng - userLocation.lng) * Math.PI / 180;
        const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
                  Math.cos(userLocation.lat * Math.PI / 180) * Math.cos(localCoords.lat * Math.PI / 180) * Math.sin(dLon/2) * Math.sin(dLon/2);
        const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
        return (R * c).toFixed(1) + " km";
    };

    if (loading) return (
        <div style={centerState}>
            <Loader2 size={40} color="#e67e22" className="animate-spin" />
            <p>Buscando ofertas cerca de ti...</p>
        </div>
    );

    return (
        <div style={container}>
            {/* CABECERA ESTILO VENDEDOR */}
            <header style={headerStyle}>
                <div>
                    <h1 style={titleStyle}>Explorar Ofertas</h1>
                    <div style={locationBadge}>
                        <MapPin size={14} /> 
                        <span>{userLocation ? "Ubicación activa" : "Ubicación no detectada"}</span>
                    </div>
                </div>
                <div style={cartFloatingCard}>
                    <ShoppingCart color="#e67e22" />
                    <div style={{fontWeight: 'bold', fontSize: '1.2rem'}}>${total.toLocaleString()}</div>
                    <span style={badgeCount}>{count}</span>
                </div>
            </header>

            {/* SECCIONES POR LOCAL */}
            {Object.keys(ofertasPorLocal).map(nombreLocal => (
                <div key={nombreLocal} style={localSection}>
                    <div style={localHeader}>
                        <div style={{display: 'flex', alignItems: 'center', gap: '10px'}}>
                            <div style={localIconCircle}><Store size={20} color="white"/></div>
                            <div>
                                <h2 style={localTitle}>{nombreLocal}</h2>
                                <p style={localSub}>{ofertasPorLocal[nombreLocal].info?.direccion || 'Dirección no disponible'}</p>
                            </div>
                        </div>
                        <div style={distanceTag}>
                            {calcularDistancia(ofertasPorLocal[nombreLocal].info?.location)}
                        </div>
                    </div>

                    <div style={scrollContainer}>
                        {ofertasPorLocal[nombreLocal].productos.map(prod => (
                            <div key={prod._id} style={productCard}>
                                <div style={imageBox}>
                                    {/* CLAVE: Usamos 'url' que es como lo guarda el vendedor */}
                                    {prod.url ? (
                                        <img src={prod.url} alt={prod.producto} style={imgStyle} />
                                    ) : (
                                        <Package size={30} color="#cbd5e1" />
                                    )}
                                    {prod.stock <= 3 && prod.stock > 0 && <span style={lastUnits}>¡Últimas {prod.stock}!</span>}
                                </div>
                                <div style={infoBox}>
                                    <h4 style={prodTitle}>{prod.producto}</h4>
                                    <div style={priceContainer}>
                                        <span style={newPrice}>${prod.precioNuevo}</span>
                                        <span style={oldPrice}>${prod.precioViejo}</span>
                                    </div>
                                    <button 
                                        style={prod.stock > 0 ? btnAdd : btnDisabled}
                                        onClick={() => addToCart(prod)}
                                        disabled={prod.stock <= 0}
                                    >
                                        <Plus size={16} /> Agregar
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            ))}
        </div>
    );
};

// --- ESTILOS ---
const container = { padding: '20px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'system-ui' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' };
const titleStyle = { fontSize: '2rem', fontWeight: '900', color: '#1e293b', margin: 0 };
const locationBadge = { display: 'flex', alignItems: 'center', gap: '5px', color: '#64748b', fontSize: '0.85rem', marginTop: '5px' };
const cartFloatingCard = { background: 'white', padding: '10px 20px', borderRadius: '50px', display: 'flex', alignItems: 'center', gap: '15px', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', border: '1px solid #f1f5f9' };
const badgeCount = { background: '#e67e22', color: 'white', width: '24px', height: '24px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.75rem', fontWeight: 'bold' };

const localSection = { marginBottom: '40px' };
const localHeader = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' };
const localIconCircle = { background: '#1e293b', width: '40px', height: '40px', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const localTitle = { margin: 0, fontSize: '1.2rem', color: '#1e293b', fontWeight: 'bold' };
const localSub = { margin: 0, fontSize: '0.85rem', color: '#94a3b8' };
const distanceTag = { background: '#f1f5f9', color: '#1e293b', padding: '5px 12px', borderRadius: '20px', fontSize: '0.8rem', fontWeight: 'bold' };

const scrollContainer = { display: 'flex', gap: '20px', overflowX: 'auto', paddingBottom: '15px', scrollbarWidth: 'none' };
const productCard = { minWidth: '220px', background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', overflow: 'hidden', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' };
const imageBox = { height: '150px', background: '#f8fafc', position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'cover' };
const lastUnits = { position: 'absolute', bottom: '8px', left: '8px', background: '#ef4444', color: 'white', fontSize: '0.65rem', padding: '2px 8px', borderRadius: '5px', fontWeight: 'bold' };

const infoBox = { padding: '15px' };
const prodTitle = { margin: '0 0 10px 0', fontSize: '1rem', color: '#1e293b', textTransform: 'capitalize' };
const priceContainer = { display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '15px' };
